def load_config(path: str):
    with open(path, "r", encoding="utf-8") as f:
        data = json.load(f)

    vhosts = []
    for item in data.get("vhosts", []):
        vhosts.append(
            VHostSpec(
                name=item["name"],
                tracing=item.get("tracing", False),
                description=item.get("description", ""),
                tags=item.get("tags", []),
            )
        )

    users = []
    for item in data.get("users", []):
        perms = {}
        for vhost_name, p in item.get("permissions", {}).items():
            perms[vhost_name] = Permission(
                configure=p.get("configure", ".*"),
                write=p.get("write", ".*"),
                read=p.get("read", ".*"),
            )
        users.append(
            UserSpec(
                name=item["name"],
                password=item.get("password"),
                tags=item.get("tags", []),
                permissions=perms,
            )
        )

    return {"vhosts": vhosts, "users": users}


